import { NextRequest, NextResponse } from 'next/server';
import sharp from 'sharp';
import { createClient } from '@supabase/supabase-js';

// ─────────────────────────────────────────────────────────────────────────────
// Embedded DejaVu Sans Cyrillic+Latin subset
// ─────────────────────────────────────────────────────────────────────────────
const FONT_R = "";
const FONT_B = "";

function ff(): string {
  return `<style>
    @font-face { font-family:"KF"; font-weight:normal; src:url("data:font/truetype;base64,${FONT_R}"); }
    @font-face { font-family:"KF"; font-weight:bold;   src:url("data:font/truetype;base64,${FONT_B}"); }
  </style>`;
}

// ─────────────────────────────────────────────────────────────────────────────
// Category styles
// ─────────────────────────────────────────────────────────────────────────────
interface CS { accent:string; bg1:string; bg2:string; panel:string; text:string; sub:string; badge:string; cta:string; specLabel:string; }
const CAT: Record<string,CS> = {
  'Одяг та взуття':       { accent:'#c8a84b',bg1:'#080808',bg2:'#141414',panel:'#0c0c0c',text:'#ffffff',sub:'#999999',badge:'ВЗУТТЯ',   cta:'ОБРАТИ РОЗМІР',  specLabel:'ХАРАКТЕРИСТИКИ' },
  'Тактичне спорядження': { accent:'#5a8a3c',bg1:'#0a0f08',bg2:'#141e0f',panel:'#0d1509',text:'#e8f0e0',sub:'#8aa87a',badge:'ТАКТИКА',  cta:'ЗАМОВИТИ',       specLabel:'ПАРАМЕТРИ'      },
  'Електроніка':          { accent:'#4a9eff',bg1:'#050b18',bg2:'#0a1628',panel:'#070e1d',text:'#e8f2ff',sub:'#6699cc',badge:'ТЕХНІКА',  cta:'КУПИТИ',         specLabel:'СПЕЦИФІКАЦІЯ'   },
  'Спорт та хобі':        { accent:'#ff6b35',bg1:'#080d18',bg2:'#0e1828',panel:'#0a1020',text:'#fff0e8',sub:'#cc8866',badge:'СПОРТ',    cta:'ЗАМОВИТИ',       specLabel:'ПЕРЕВАГИ'       },
  'Дім та сад':           { accent:'#6ab04c',bg1:'#080c08',bg2:'#101810',panel:'#0a0e0a',text:'#f0f8e8',sub:'#88aa77',badge:'ДІМ',      cta:'ЗАМОВИТИ',       specLabel:'ПЕРЕВАГИ'       },
  "Краса та здоров\'я":  { accent:'#e87aa0',bg1:'#160a10',bg2:'#241018',panel:'#1a0c14',text:'#fce8f0',sub:'#cc8899',badge:'КРАСА',    cta:'СПРОБУВАТИ',     specLabel:'ВЛАСТИВОСТІ'    },
  'Авто та мото':         { accent:'#e0a020',bg1:'#0a0a0a',bg2:'#1a1a1a',panel:'#111111',text:'#f5f0e0',sub:'#aa9966',badge:'АВТО',     cta:'ЗАМОВИТИ',       specLabel:'ПАРАМЕТРИ'      },
  'Іграшки':              { accent:'#8855ee',bg1:'#08080f',bg2:'#12122a',panel:'#0e0e22',text:'#f0e8ff',sub:'#9977cc',badge:'ДІТИ',     cta:'ОБРАТИ',         specLabel:'ПЕРЕВАГИ'       },
  'default':              { accent:'#c8a84b',bg1:'#0d0d0d',bg2:'#1a1a1a',panel:'#111111',text:'#ffffff',sub:'#aaaaaa',badge:'ТОВАР',    cta:'ЗАМОВИТИ ЗАРАЗ', specLabel:'ПЕРЕВАГИ'       },
};

// ─────────────────────────────────────────────────────────────────────────────
// SVG helpers
// ─────────────────────────────────────────────────────────────────────────────
function esc(s: string): string {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function hex2rgb(h: string): [number,number,number] {
  return [parseInt(h.slice(1,3),16),parseInt(h.slice(3,5),16),parseInt(h.slice(5,7),16)];
}
function rgba(h: string, a: number): string {
  const [r,g,b]=hex2rgb(h); return `rgba(${r},${g},${b},${a})`;
}

function wrapText(text: string, maxChars: number): string[] {
  const words = text.split(' ');
  const lines: string[] = [];
  let cur = '';
  for (const w of words) {
    if ((cur+' '+w).trim().length > maxChars && cur) { lines.push(cur.trim()); cur=w; }
    else cur=(cur+' '+w).trim();
  }
  if (cur) lines.push(cur);
  return lines;
}

// Text block with optional icon circle
function specRow(x: number, y: number, icon: string, label: string, value: string, accent: string, textColor: string, last: boolean): string {
  const vLines = wrapText(value, 36);
  const [r,g,b]=hex2rgb(accent);
  let out = '';
  // Icon circle
  out += `<circle cx="${x+16}" cy="${y+16}" r="16" fill="rgba(${r},${g},${b},0.15)"/>`;
  out += `<circle cx="${x+16}" cy="${y+16}" r="16" fill="none" stroke="rgba(${r},${g},${b},0.4)" stroke-width="1"/>`;
  out += `<text x="${x+16}" y="${y+22}" text-anchor="middle" font-family="KF" font-size="13" fill="${accent}">${esc(icon)}</text>`;
  // Label
  out += `<text x="${x+42}" y="${y+11}" font-family="KF" font-weight="bold" font-size="10" fill="${accent}" letter-spacing="1.5">${esc(label)}</text>`;
  // Value lines
  vLines.forEach((l,i)=>{
    out += `<text x="${x+42}" y="${y+27+(i*17)}" font-family="KF" font-size="14" fill="${textColor}">${esc(l)}</text>`;
  });
  // Separator
  if (!last) {
    const rowH = Math.max(38, 27+vLines.length*17);
    out += `<line x1="${x}" y1="${y+rowH+8}" x2="${x+400}" y2="${y+rowH+8}" stroke="rgba(255,255,255,0.07)" stroke-width="0.5"/>`;
  }
  return out;
}

// Callout pill with optional arrow line
function callout(x: number, y: number, toX: number, toY: number, text: string, accent: string, side: 'left'|'right'): string {
  const lines = wrapText(text, 22);
  const w = 160, h = lines.length*18+20;
  const bx = side==='right' ? x-w : x;
  let out = '';
  // Arrow line
  out += `<line x1="${toX}" y1="${toY}" x2="${bx+(side==='right'?w:0)}" y2="${y+h/2}" stroke="${accent}" stroke-width="1" opacity="0.7" marker-end="url(#arr)"/>`;
  // Dot at arrow origin
  out += `<circle cx="${toX}" cy="${toY}" r="4" fill="${accent}" opacity="0.8"/>`;
  out += `<circle cx="${toX}" cy="${toY}" r="7" fill="${accent}" opacity="0.2"/>`;
  // Box
  out += `<rect x="${bx}" y="${y}" width="${w}" height="${h}" rx="7" fill="rgba(8,8,8,0.92)"/>`;
  out += `<rect x="${bx}" y="${y}" width="${side==='right'?1:3}" height="${h}" rx="1" fill="${accent}"/>`;
  // Text
  lines.forEach((l,i)=>{
    out += `<text x="${bx+(side==='right'?w-8:10)}" y="${y+18+i*18}" text-anchor="${side==='right'?'end':'start'}" font-family="KF" font-size="13" fill="#ffffff">${esc(l)}</text>`;
  });
  return out;
}

function pickIcon(text: string): string {
  const t=text.toLowerCase();
  if(t.match(/шкір|leather/))      return '🦎';
  if(t.match(/підошв|sole/))       return '👟';
  if(t.match(/водо|water|вологост/)) return '💧';
  if(t.match(/матер|тканин/))      return '🧵';
  if(t.match(/розмір|об.єм|літр/)) return '📐';
  if(t.match(/міцн|зносостійк/))   return '💪';
  if(t.match(/зручн|comfort/))     return '✋';
  if(t.match(/відділ|кишен/))      return '🎒';
  if(t.match(/захист|protect/))    return '🛡️';
  if(t.match(/dpi|точн/))          return '⚡';
  if(t.match(/батар|заряд/))       return '🔋';
  if(t.match(/бездрот|wireless/))  return '📡';
  if(t.match(/тактичн/))           return '🎯';
  return '✅';
}

// ─────────────────────────────────────────────────────────────────────────────
// Layout builders — pure SVG strings, composited by sharp
// ─────────────────────────────────────────────────────────────────────────────

// LAYOUT A: Shoe/Clothing — product left, specs panel right, 3 callouts
function buildLayoutA(
  W:number, H:number, C:CS, accent:string,
  name:string, specs:{icon:string;label:string;value:string}[],
  callouts:{text:string;toX:number;toY:number;side:'left'|'right'}[],
): string {
  const nameLines = wrapText(name, 22);
  const PX=590; // panel x
  
  let inner = '';
  
  // BG gradient
  inner += `<defs>
    ${ff()}
    <linearGradient id="bgG" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="${C.bg1}"/>
      <stop offset="100%" stop-color="${C.bg2}"/>
    </linearGradient>
    <linearGradient id="ov" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="${C.bg1}" stop-opacity="0.96"/>
      <stop offset="52%" stop-color="${C.bg1}" stop-opacity="0.45"/>
      <stop offset="100%" stop-color="${C.bg1}" stop-opacity="0.92"/>
    </linearGradient>
    <marker id="arr" markerWidth="7" markerHeight="5" refX="7" refY="2.5" orient="auto">
      <polygon points="0 0, 7 2.5, 0 5" fill="${accent}" opacity="0.85"/>
    </marker>
  </defs>`;
  
  inner += `<rect width="${W}" height="${H}" fill="url(#bgG)"/>`;
  inner += `<rect width="${W}" height="${H}" fill="url(#ov)"/>`;
  
  // Right panel
  inner += `<rect x="${PX}" y="0" width="${W-PX}" height="${H}" fill="${C.panel}" opacity="0.90"/>`;
  inner += `<rect x="${PX}" y="0" width="4" height="${H}" fill="${accent}"/>`;
  
  // Badge
  inner += `<rect x="${PX+24}" y="44" width="92" height="26" rx="13" fill="${rgba(accent,0.18)}"/>`;
  inner += `<rect x="${PX+24}" y="44" width="92" height="26" rx="13" fill="none" stroke="${rgba(accent,0.5)}" stroke-width="1"/>`;
  inner += `<text x="${PX+70}" y="62" text-anchor="middle" font-family="KF" font-weight="bold" font-size="11" fill="${accent}" letter-spacing="2">${C.badge}</text>`;
  
  // Accent bar
  inner += `<rect x="${PX+24}" y="88" width="52" height="4" rx="2" fill="${accent}"/>`;
  
  // Title
  let ty = 122;
  nameLines.forEach((l,i)=>{
    inner += `<text x="${PX+24}" y="${ty}" font-family="KF" font-weight="bold" font-size="${nameLines.length>2?20:24}" fill="${i===0?'#ffffff':accent}">${esc(l)}</text>`;
    ty += nameLines.length>2 ? 26 : 30;
  });
  
  // Divider
  inner += `<line x1="${PX+24}" y1="${ty+10}" x2="${W-30}" y2="${ty+10}" stroke="${rgba(accent,0.3)}" stroke-width="1"/>`;
  
  // Spec label
  inner += `<text x="${PX+24}" y="${ty+34}" font-family="KF" font-weight="bold" font-size="10" fill="${accent}" letter-spacing="2">${C.specLabel}</text>`;
  
  // Spec rows
  let sy = ty+56;
  const rowGap = 64;
  specs.slice(0,4).forEach((s,i)=>{
    inner += specRow(PX+24, sy, s.icon, s.label, s.value, accent, C.text, i===Math.min(specs.length,4)-1);
    sy += rowGap;
  });
  
  // CTA
  inner += `<rect x="${PX+24}" y="${H-110}" width="${W-PX-48}" height="54" rx="12" fill="${accent}"/>`;
  inner += `<text x="${PX+24+(W-PX-48)/2}" y="${H-76}" text-anchor="middle" font-family="KF" font-weight="bold" font-size="15" fill="#000000" letter-spacing="1">${C.cta}</text>`;
  
  // Delivery
  inner += `<text x="${PX+24+(W-PX-48)/2}" y="${H-40}" text-anchor="middle" font-family="KF" font-size="11" fill="${rgba('#ffffff',0.3)}">Швидка доставка по всій Україні</text>`;
  
  // Decorative diamond top-left
  inner += `<polygon points="28,28 52,28 52,52 28,52" fill="${accent}" opacity="0.7" transform="rotate(45 40 40)"/>`;
  
  // Callouts
  callouts.slice(0,3).forEach((c,i)=>{
    inner += callout(c.side==='right'?c.toX+20:c.toX-180, c.toY-19, c.toX, c.toY, c.text, accent, c.side);
  });
  
  return `<?xml version="1.0" encoding="UTF-8"?>
<svg width="${W}" height="${H}" xmlns="http://www.w3.org/2000/svg">
  ${inner}
</svg>`;
}

